module RefModule(
    input in,
    output reg out,  // Change the output declaration to reg
    input clk
);reg prev_in;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (in && !prev_in) begin
            out <= 1'b1;
        end else begin
            out <= 1'b0;
        end
        prev_in <= in;
    end

endmodule
